+    DEBT_HOOK_CLEANUP_MISMATCH, DEBT_HYDRATION_BOUNDARY_CONFLICT,
+    DEBT_SUSPENSE_BOUNDARY_CONFLICT, DEBT_UNRESOLVED_CONTEXT,
+    GLOBAL_COHERENCE_BEAD_ID, GLOBAL_COHERENCE_SCHEMA_VERSION,
+};
