+            if row.sample_count > 0
+                && row.confidence_low_delta_millionths <= row.confidence_high_delta_millionths
+                && row.protocol_hash == fixture.protocol_hash
+                && delta >= threshold
+                && row.confidence_low_delta_millionths > 0
