+// ===========================================================================
+// 24. Large DAG
+// ===========================================================================
+
+#[test]
+fn large_chain_dag() {
+    let mut scm = StructuralCausalModel::new();
+    let n = 20;
+    for i in 0..n {
+        scm.add_node(node(
+            &format!("N_{i}"),
+            NodeRole::Endogenous,
+            VariableDomain::RiskBelief,
+        ))
+        .unwrap();
+    }
+    for i in 0..(n - 1) {
+        scm.add_edge(edge(
+            &format!("N_{i}"),
+            &format!("N_{}", i + 1),
+            EdgeSign::Positive,
+            500_000,
+        ))
+        .unwrap();
+    }
+    assert!(scm.has_path(&"N_0".to_string(), &format!("N_{}", n - 1)));
+    let order = scm.topological_order();
+    assert_eq!(order.len(), n);
+}
